#define _GNU_SOURCE
#include <stdio.h>
#include <pthread.h>
#include <unistd.h>

static pthread_mutex_t mtx;

static void *thread_low(void *arg) {
    (void)arg;
    pthread_mutex_lock(&mtx);
    printf("LOW: acquired mutex\n");
    usleep(100000);
    printf("LOW: released mutex\n");
    pthread_mutex_unlock(&mtx);
    return NULL;
}

static void *thread_high(void *arg) {
    (void)arg;
    usleep(10000);
    printf("HIGH: waiting for mutex\n");
    pthread_mutex_lock(&mtx);
    printf("HIGH: acquired mutex\n");
    pthread_mutex_unlock(&mtx);
    printf("HIGH: done\n");
    return NULL;
}

static void *thread_medium(void *arg) {
    (void)arg;
    usleep(20000);
    for (volatile int i = 0; i < 50000000; i++);
    return NULL;
}

int main(void) {
    pthread_mutexattr_t attr;
    pthread_mutexattr_init(&attr);
    pthread_mutexattr_setprotocol(&attr, PTHREAD_PRIO_INHERIT);
    pthread_mutex_init(&mtx, &attr);
    pthread_mutexattr_destroy(&attr);

    pthread_t tl, th, tm;
    pthread_create(&tl, NULL, thread_low, NULL);
    pthread_create(&th, NULL, thread_high, NULL);
    pthread_create(&tm, NULL, thread_medium, NULL);

    pthread_join(tl, NULL);
    pthread_join(th, NULL);
    pthread_join(tm, NULL);

    pthread_mutex_destroy(&mtx);
    return 0;
}

